/**
 * Generated by `createservice miniapp.GetB2CAppInfoService --type queries`
 */

const { z } = require('zod')

const { GQLCustomSchema } = require('@open-condo/keystone/schema')

const { REMOTE_SYSTEM } = require('@dev-portal-api/domains/common/constants/common')
const { productionClient, developmentClient } = require('@dev-portal-api/domains/common/utils/serverClients')
const { CondoB2CAppWithInfoGql } = require('@dev-portal-api/domains/condo/gql')
const access = require('@dev-portal-api/domains/miniapp/access/GetB2CAppInfoService')
const { PROD_ENVIRONMENT } = require('@dev-portal-api/domains/miniapp/constants/publishing')


const GetB2CAppInfoService = new GQLCustomSchema('GetB2CAppInfoService', {
    types: [
        {
            access: true,
            type: 'input GetB2CAppInfoInput { app: B2CAppWhereUniqueInput!, environment: AppEnvironment! }',
        },
        {
            access: true,
            type: 'type B2CAppCurrentBuild { id: String!, version: String! }',
        },
        {
            access: true,
            type: 'type GetB2CAppInfoOutput { id: String!, environment: AppEnvironment!, currentBuild: B2CAppCurrentBuild, isGlobal: Boolean! }',
        },
    ],
    
    queries: [
        {
            access: access.canGetB2CAppInfo,
            schema: 'getB2CAppInfo (data: GetB2CAppInfoInput!): GetB2CAppInfoOutput',
            resolver: async (parent, args, context, info, extra = {}) => {
                const { data: { app: { id }, environment } } = args

                const serverClient = environment === PROD_ENVIRONMENT
                    ? productionClient
                    : developmentClient

                const b2cApp = await serverClient.findExportedModel({
                    modelGql: CondoB2CAppWithInfoGql,
                    id,
                    context,
                })

                if (!b2cApp) return null

                // NOTE: build version in condo might contain suffix obtained via generateB2CAppBuildHash
                // User does not know about this suffix, so we need to remove it
                const currentBuild = b2cApp.currentBuild

                if (!currentBuild || !currentBuild.importId || !currentBuild.importRemoteSystem) {
                    return { id: b2cApp.id, environment, currentBuild, isGlobal: b2cApp.isGlobal }
                }

                const buildImportId = currentBuild.importId // <uuid> or <uuid>-<hash>
                const buildImportRemoteSystem = currentBuild.importRemoteSystem // <remote-system> or anything else
                const lastDashIndex = buildImportId.lastIndexOf('-') ?? -1
                const importIdPrefix = lastDashIndex === -1 ? buildImportId : buildImportId.substring(0, lastDashIndex)
                const { success: isUuidPrefixed } = z.uuid().safeParse(importIdPrefix)
                const importIdSuffix = lastDashIndex === -1 ? '' : buildImportId.substring(lastDashIndex + 1)

                // Versions will contains same hash, so omit it if import id contains it
                if (
                    buildImportRemoteSystem === REMOTE_SYSTEM &&
                    isUuidPrefixed &&
                    importIdSuffix &&
                    typeof currentBuild.version === 'string' &&
                    currentBuild.version.endsWith(`-${importIdSuffix}`)
                ) {
                    currentBuild.version = currentBuild.version.slice(0, -importIdSuffix.length - 1)
                }

                return { id: b2cApp.id, environment, currentBuild, isGlobal: b2cApp.isGlobal }
            },
        },
    ],
    
})

module.exports = {
    GetB2CAppInfoService,
}
